$(()=>{$.getJSON("https://api.github.com/repos/cryptomator/cryptomator",t=>{$("#github-stargazers").text(e(t.stargazers_count))}).fail(()=>{console.error("Error fetching repository data.")});function e(e){if(e>=1e3&&e<1e6){const t=(e/1e3).toFixed(1);return t.endsWith(".0")?t.slice(0,-2)+"k":t+"k"}if(e>=1e6){const t=(e/1e6).toFixed(1);return t.endsWith(".0")?t.slice(0,-2)+"M":t+"M"}return e}})